import { formatDevBuildStatusLine, getDevBuildSummary, isDevBuildActive, } from "../buildInfo.js";
import { getConfig, hasCredentials } from "../config.js";
import { checkForUpdate, formatUpdateMessage } from "../updates.js";
export async function runStatus(currentVersion, platform, pluginRoot, scriptUrl) {
    const config = getConfig();
    const devBuildActive = isDevBuildActive(platform, scriptUrl);
    const { current, latest, updateAvailable } = await checkForUpdate(currentVersion, platform);
    console.log(`Plugin: ${devBuildActive ? "Bitfab Dev" : "Bitfab"}`);
    console.log(`Service URL: ${config.serviceUrl}`);
    const versionSuffix = updateAvailable && latest
        ? ` (${formatUpdateMessage(latest, platform)})`
        : "";
    console.log(`Version: v${current}${versionSuffix}`);
    if (devBuildActive && pluginRoot) {
        const summary = getDevBuildSummary(pluginRoot);
        if (summary) {
            console.log(formatDevBuildStatusLine(summary));
            console.log(`Plugin path: ${summary.pluginRoot}`);
        }
    }
    if (!hasCredentials()) {
        console.log("Status: not authenticated");
        console.log(`\nRun ${platform.loginHint} to authenticate.`);
        return;
    }
    console.log("Status: authenticated");
}
